//-----------------------------------		XExamClmtTime    -----------------------------------------------
function XExamClmtTimeUnits() {}
XExamClmtTimeUnits.dataBinding = "/ds/EnterVariableData/TrialNotice/xExamClmtTimeUnits";
XExamClmtTimeUnits.tabIndex = __tabIdx++;
XExamClmtTimeUnits.helpText = "Select unit time";
XExamClmtTimeUnits.mandatoryOn = [XExamClmtTime.dataBinding];
XExamClmtTimeUnits.isMandatory = function()
{	var val = Services.getValue(XExamClmtTime.dataBinding);
	return( null != val && "" != val );
}	
XExamClmtTimeUnits.isTemporary = function(){  return true; }
XExamClmtTimeUnits.enableOn = [XExamClmtTime.dataBinding];
XExamClmtTimeUnits.isEnabled = function(){ return XExamClmtTime.isEnabled();}
XExamClmtTimeUnits.logicOn = [SelectItemLsA.dataBinding];
XExamClmtTimeUnits.logic = function()
{	if('STA'!=Services.getValue(SelectItemLsA.dataBinding))
	Services.setValue(XExamClmtTimeUnits.dataBinding,"");			
}								
//-----------------------------------		END XExamClmtTime    -----------------------------------------------
